    85→void initializeMutex(pthread_mutex_t& mutex) {
    86→  pthread_mutexattr_t attribute;
    87→  pthread_mutexattr_init(&attribute);
    88→  pthread_mutexattr_setpshared(&attribute, PTHREAD_PROCESS_SHARED);
    89→  pthread_mutexattr_setrobust(&attribute, PTHREAD_MUTEX_ROBUST);
    90→  pthread_mutex_init(&mutex, &attribute);
    91→}
