   123→void HotRestartImpl::registerUdpForwardingListener(
   124→    Network::Address::InstanceConstSharedPtr address,
   125→    std::shared_ptr<Network::UdpListenerConfig> listener_config) {
   126→  as_child_.registerUdpForwardingListener(address, listener_config);
   127→}
