   129→OptRef<Network::ParentDrainedCallbackRegistrar> HotRestartImpl::parentDrainedCallbackRegistrar() {
   130→  return as_child_;
   131→}
   132→
   133→void HotRestartImpl::initialize(Event::Dispatcher& dispatcher, Server::Instance& server) {
   134→  as_parent_.initialize(dispatcher, server);
   135→  as_child_.initialize(dispatcher);
   136→}
