   156→bool RpcStream::replyIsExpectedType(const HotRestartMessage* proto,
   157→                                    HotRestartMessage::Reply::ReplyCase oneof_type) const {
   158→  return proto != nullptr && proto->requestreply_case() == HotRestartMessage::kReply &&
   159→         proto->reply().reply_case() == oneof_type;
