   183→// While in use, recv_buf_ is always >= MaxSendmsgSize. In between messages, it is kept empty,
   184→// to be grown back to MaxSendmsgSize at the start of the next message.
   185→void RpcStream::initRecvBufIfNewMessage() {
   186→  if (recv_buf_.empty()) {
   187→    ASSERT(cur_msg_recvd_bytes_ == 0);
   188→    ASSERT(!expected_proto_length_.has_value());
   189→    recv_buf_.resize(MaxSendmsgSize);
   190→  }
