   193→// Must only be called when recv_buf_ contains a full proto. Returns that proto, and resets all of
   194→// our receive-buffering state back to empty, to await a new message.
   195→std::unique_ptr<HotRestartMessage> RpcStream::parseProtoAndResetState() {
   196→  auto ret = std::make_unique<HotRestartMessage>();
   197→  RELEASE_ASSERT(
   198→      ret->ParseFromArray(recv_buf_.data() + sizeof(uint64_t), expected_proto_length_.value()),
   199→      "failed to parse a HotRestartMessage.");
   200→  recv_buf_.resize(0);
   201→  cur_msg_recvd_bytes_ = 0;
   202→  expected_proto_length_.reset();
