   200→void HotRestartingParent::Internal::recordDynamics(HotRestartMessage::Reply::Stats* stats,
   201→                                                   const std::string& name,
   202→                                                   Stats::StatName stat_name) {
   203→  // Compute an array of spans describing which components of the stat name are
   204→  // dynamic. This is needed so that when the child recovers the StatName, it
   205→  // correlates with how the system generates those stats, with the same exact
   206→  // components using a dynamic representation.
   207→  //
   208→  // See https://github.com/envoyproxy/envoy/issues/9874 for more details.
   209→  Stats::DynamicSpans spans = server_->stats().symbolTable().getDynamicSpans(stat_name);
   210→
   211→  // Convert that C++ structure (controlled by stat_merger.cc) into a protobuf
   212→  // for serialization.
   213→  if (!spans.empty()) {
   214→    HotRestartMessage::Reply::RepeatedSpan spans_proto;
   215→    for (const Stats::DynamicSpan& span : spans) {
   216→      HotRestartMessage::Reply::Span* span_proto = spans_proto.add_spans();
   217→      span_proto->set_first(span.first);
   218→      span_proto->set_last(span.second);
   219→    }
   220→    (*stats->mutable_dynamics())[name] = spans_proto;
   221→  }
   222→}
