   102→void HotRestartingChild::onForwardedUdpPacket(uint32_t worker_index, Network::UdpRecvData&& data) {
   103→  auto addr_and_listener =
   104→      udp_forwarding_context_.getListenerForDestination(*data.addresses_.local_);
   105→  if (addr_and_listener.has_value()) {
   106→    auto [addr, listener_config] = *addr_and_listener;
   107→    // We send to the worker index from the parent instance.
   108→    // In the case that the number of workers changes between instances,
   109→    // or the quic connection id generator changes how it selects worker
   110→    // ids, the hot restart packet transfer will fail.
   111→    //
   112→    // One option would be to dispatch an onData call to have the receiving
   113→    // worker forward the packet if the calculated destination differs from
   114→    // the parent instance worker index; however, this would require
   115→    // temporarily disabling kernel_worker_routing_ in each instance of
   116→    // ActiveQuicListener, and a much more convoluted pipeline to collect
   117→    // the set of destinations (listenerWorkerRouter doesn't currently
   118→    // expose the actual listeners.)
   119→    //
   120→    // Since the vast majority of hot restarts will change neither of these
   121→    // things, this implementation is "pretty good", and much better than no
   122→    // hot restart capability at all.
   123→    listener_config->listenerWorkerRouter(*addr).deliver(worker_index, std::move(data));
   124→  }
   125→}
