   201→absl::optional<HotRestart::AdminShutdownResponse>
   202→HotRestartingChild::sendParentAdminShutdownRequest() {
   203→  if (parent_terminated_) {
   204→    return absl::nullopt;
   205→  }
   206→
   207→  HotRestartMessage wrapped_request;
   208→  wrapped_request.mutable_request()->mutable_shutdown_admin();
   209→  main_rpc_stream_.sendHotRestartMessage(parent_address_, wrapped_request);
   210→
   211→  std::unique_ptr<HotRestartMessage> wrapped_reply =
   212→      main_rpc_stream_.receiveHotRestartMessage(RpcStream::Blocking::Yes);
   213→  RELEASE_ASSERT(main_rpc_stream_.replyIsExpectedType(wrapped_reply.get(),
   214→                                                      HotRestartMessage::Reply::kShutdownAdmin),
   215→                 "Hot restart parent did not respond as expected to ShutdownParentAdmin.");
   216→  return HotRestart::AdminShutdownResponse{
   217→      static_cast<time_t>(
   218→          wrapped_reply->reply().shutdown_admin().original_start_time_unix_seconds()),
   219→      wrapped_reply->reply().shutdown_admin().enable_reuse_port_default()};
