   222→void HotRestartingChild::sendParentTerminateRequest() {
   223→  if (parent_terminated_) {
   224→    return;
   225→  }
   226→  allDrainsImplicitlyComplete();
   227→
   228→  HotRestartMessage wrapped_request;
   229→  wrapped_request.mutable_request()->mutable_terminate();
   230→  main_rpc_stream_.sendHotRestartMessage(parent_address_, wrapped_request);
   231→  parent_terminated_ = true;
   232→
   233→  // Note that the 'generation' counter needs to retain the contribution from
   234→  // the parent.
   235→  if (stat_merger_ != nullptr) {
   236→    stat_merger_->retainParentGaugeValue(hot_restart_generation_stat_name_);
   237→
   238→    // Now it is safe to forget our stat transferral state.
   239→    //
   240→    // This destruction is actually important far beyond memory efficiency. The
   241→    // scope-based temporary counter logic relies on the StatMerger getting
   242→    // destroyed once hot restart's stat merging is all done. (See stat_merger.h
   243→    // for details).
   244→    stat_merger_.reset();
   245→  }
   246→}
