   248→void HotRestartingChild::mergeParentStats(Stats::Store& stats_store,
   249→                                          const HotRestartMessage::Reply::Stats& stats_proto) {
   250→  if (!stat_merger_) {
   251→    stat_merger_ = std::make_unique<Stats::StatMerger>(stats_store);
   252→    hot_restart_generation_stat_name_ = hotRestartGeneration(*stats_store.rootScope()).statName();
   253→  }
   254→
   255→  // Convert the protobuf for serialized dynamic spans into the structure
   256→  // required by StatMerger.
   257→  Stats::StatMerger::DynamicsMap dynamics;
   258→  for (const auto& iter : stats_proto.dynamics()) {
   259→    Stats::DynamicSpans& spans = dynamics[iter.first];
   260→    for (int i = 0; i < iter.second.spans_size(); ++i) {
   261→      const HotRestartMessage::Reply::Span& span_proto = iter.second.spans(i);
   262→      spans.push_back(Stats::DynamicSpan(span_proto.first(), span_proto.last()));
   263→    }
   264→  }
   265→  stat_merger_->mergeStats(stats_proto.counter_deltas(), stats_proto.gauges(), dynamics);
   266→}
