   268→absl::Status HotRestartingChild::onSocketEventUdpForwarding() {
   269→  std::unique_ptr<HotRestartMessage> wrapped_request;
   270→  while ((wrapped_request =
   271→              udp_forwarding_rpc_stream_.receiveHotRestartMessage(RpcStream::Blocking::No))) {
   272→    if (wrapped_request->requestreply_case() == HotRestartMessage::kReply) {
   273→      ENVOY_LOG_PERIODIC(
   274→          error, std::chrono::seconds(5),
   275→          "HotRestartMessage reply received on UdpForwarding (we want only requests); ignoring.");
   276→      continue;
   277→    }
   278→    switch (wrapped_request->request().request_case()) {
   279→    case HotRestartMessage::Request::kForwardedUdpPacket: {
   280→      const auto& req = wrapped_request->request().forwarded_udp_packet();
   281→      Network::UdpRecvData packet;
   282→      auto local_or_error = Network::Utility::resolveUrl(req.local_addr());
   283→      RETURN_IF_NOT_OK(local_or_error.status());
   284→      packet.addresses_.local_ = *local_or_error;
   285→      auto peer_or_error = Network::Utility::resolveUrl(req.peer_addr());
   286→      RETURN_IF_NOT_OK(peer_or_error.status());
   287→      packet.addresses_.peer_ = *peer_or_error;
   288→      if (!packet.addresses_.local_ || !packet.addresses_.peer_) {
   289→        break;
   290→      }
   291→      packet.receive_time_ =
   292→          MonotonicTime(std::chrono::microseconds{req.receive_time_epoch_microseconds()});
   293→      packet.buffer_ = std::make_unique<Buffer::OwnedImpl>(req.payload());
   294→      onForwardedUdpPacket(req.worker_index(), std::move(packet));
   295→      break;
   296→    }
   297→    default: {
   298→      ENVOY_LOG(
   299→          error,
   300→          "child sent a request other than ForwardedUdpPacket on udp forwarding socket; ignoring.");
   301→      break;
   302→    }
   303→    }
   304→  }
   305→  return absl::OkStatus();
   306→}
